+CPUPerformanceInterface::CPUPerformance::CPUPerformance() {
+  _num_procs = 0;
+  _stathz = 0;
+  _jvm_ticks = JVMTicks();
+  _cpus = nullptr;
+  _total_csr_nanos= 0;
+  _jvm_context_switches = 0;
