+int CPUPerformanceInterface::CPUPerformance::init_stathz(void) {
+  struct clockinfo ci;
+  size_t length = sizeof(ci);
+  int mib[] = { CTL_KERN, KERN_CLOCKRATE };
+  const u_int miblen = sizeof(mib) / sizeof(mib[0]);
+
+  if (sysctl(mib, miblen, &ci, &length, nullptr, 0) == -1) {
+    return OS_ERR;
+  }
+
+  _stathz = ci.stathz;
+
+  return OS_OK;
+}
