+uint64_t CPUPerformanceInterface::CPUPerformance::tvtoticks(struct timeval tv) {
+  uint64_t ticks = 0;
+  ticks += (uint64_t)tv.tv_sec * _stathz;
+  ticks += (uint64_t)tv.tv_usec * _stathz / MICROS_PER_SEC;
+  return ticks;
+}
